/**
 * Updates a user's profile in the PostgreSQL database.
 * @param {string|number} userId - The ID of the user to update.
 * @param {object} profileData - An object containing the fields to update (e.g., { email: 'new@example.com', name: 'New Name' }).
 * @returns {Promise<object>} - The updated user object.
 */
async function updateUserProfile(userId, profileData) {
  const fields = Object.keys(profileData);

  if (fields.length === 0) {
    return null; // Or throw an error depending on desired behavior
  }

  // Create dynamic SET clause: "field1" = $2, "field2" = $3, ...
  // Starting index at 2 because $1 is reserved for userId
  const setClause = fields.map((field, index) => `"${field}" = $${index + 2}`).join(', ');

  const values = [userId, ...Object.values(profileData)];

  const query = `
    UPDATE users
    SET ${setClause}
    WHERE id = $1
    RETURNING *;
  `;

  try {
    const { rows } = await pool.query(query, values);
    return rows[0];
  } catch (error) {
    console.error('Error updating user profile:', error);
    throw error;
  }
}

