  const cipher = crypto.createCipheriv('aes-256-cbc', Buffer.from(key), iv);
  let encrypted = cipher.update(text);
  encrypted = Buffer.concat([encrypted, cipher.final()]);
  return iv.toString('hex') + ':' + encrypted.toString('hex');
}

const crypto = require('crypto');

function encryptSensitiveData(text, secretKey) {
  // Ensure the key is 32 bytes (256 bits) for aes-256-gcm
  // Expected secretKey format: 64-character hex string or 32-byte Buffer
  const keyBuffer = Buffer.isBuffer(secretKey) ? secretKey : Buffer.from(secretKey, 'hex');
  const iv = crypto.randomBytes(16);
  const cipher = crypto.createCipheriv('aes-256-gcm', keyBuffer, iv);

  let encrypted = cipher.update(text, 'utf8', 'hex');
  encrypted += cipher.final('hex');
  const authTag = cipher.getAuthTag().toString('hex');

  // Return format: IV:AuthTag:EncryptedData
  return `${iv.toString('hex')}:${authTag}:${encrypted}`;
}

const crypto = require('crypto');

function encryptSensitiveData(text, secretKey) {
  const iv = crypto.randomBytes(16);
  // Hash the key to ensure it is 32 bytes for aes-256-cbc
  const key = crypto.createHash('sha256').update(secretKey).digest();
  const cipher = crypto.createCipheriv('aes-256-cbc', key, iv);

  let encrypted = cipher.update(text);
  encrypted = Buffer.concat([encrypted, cipher.final()]);

  return iv.toString('hex') + ':' + encrypted.toString('hex');
}

