const crypto = require('crypto');

function encryptSensitiveData(plaintext) {
  const algorithm = 'aes-256-cbc';
  // Key must be 32 bytes for aes-256-cbc. Stored in environment variable recommended.
  const key = process.env.ENCRYPTION_KEY ? Buffer.from(process.env.ENCRYPTION_KEY, 'hex') : crypto.randomBytes(32);
  const iv = crypto.randomBytes(16);

  const cipher = crypto.createCipheriv(algorithm, key, iv);
  let encrypted = cipher.update(plaintext, 'utf8', 'hex');
  encrypted += cipher.final('hex');

  // Return IV and encrypted text joined by ':' to allow decryption
  return `${iv.toString('hex')}:${encrypted}`;
}

const crypto = require('crypto');

function encryptSensitiveData(plaintext, key) {
  const iv = crypto.randomBytes(16);
  const cipher = crypto.createCipheriv('aes-256-cbc', Buffer.from(key), iv);
  let encrypted = cipher.update(plaintext, 'utf8', 'hex');
  encrypted += cipher.final('hex');
  return iv.toString('hex') + ':' + encrypted;
}
